async def human_review_node(state: CodeState) -> CodeState:
    if state['safety_score'] < 0.8:
        # Persist for human review
        checkpoint = await vex.validate_checkpoint(state)
        if not checkpoint.valid:
            raise ValueError('Checkpoint schema corrupted')

        # Human approval workflow
        approval = await vex.human_review(
            code=state['code'],
            issues=state.get('issues', []),
            context=state['requirement']
        )

        if not approval.approved:
            return {'approved': False}

    return {'approved': True}

workflow.add_node('human_review', human_review_node)
workflow.add_conditional_edges(
    'executor',
    lambda s: 'human_review' if s['safety_score'] < 0.8 else 'reviewer'
)
